validation.test_code:
void test_sem_init_success(void) {
    sem_t s;
    int rc = sem_init(&s, 0, 3);
    TEST_ASSERT_EQUAL_INT(0, rc);
    sem_destroy(&s);
}

void test_sem_getvalue_initial(void) {
    sem_t s;
    sem_init(&s, 0, 5);
    int val;
    int rc = sem_getvalue(&s, &val);
    TEST_ASSERT_EQUAL_INT(0, rc);
    TEST_ASSERT_EQUAL_INT(5, val);
    sem_destroy(&s);
}

void test_sem_wait_decrements(void) {
    sem_t s;
    sem_init(&s, 0, 3);
    sem_wait(&s);
    int val;
    sem_getvalue(&s, &val);
    TEST_ASSERT_EQUAL_INT(2, val);
    sem_destroy(&s);
}

void test_sem_three_waits(void) {
    sem_t s;
    sem_init(&s, 0, 3);
    for (int i = 0; i < 3; i++)
        sem_wait(&s);
    int val;
    sem_getvalue(&s, &val);
    TEST_ASSERT_EQUAL_INT(0, val);
    sem_destroy(&s);
}

int main(void) {
    RUN_TEST(test_sem_init_success);
    RUN_TEST(test_sem_getvalue_initial);
    RUN_TEST(test_sem_wait_decrements);
    RUN_TEST(test_sem_three_waits);
    TEST_SUMMARY();
    return _clings_failures > 0 ? 1 : 0;
}

